name = str(input("Enter your name: ")) # Get user input for name and convert it to a string
age = int(input("Enter your age: ")) # Get user input for age and convert it to an integer
print("Hello, " + name + "! You are " + str(age) + " years old.") # str(name) converts the name variable to a string, and str(age) converts the age variable to a string for concatenation in the print statement